//
//  ConnectionDeviceView.swift
//  Radiacode
//
//  Created by Pavel Marinchenko on 26.03.2023.
//

import SwiftUI

struct ConnectionDeviceView: View {

    var bluetoothDevice: BluetoothDevice

    var body: some View {
        HStack {
            DeviceView(
                device: bluetoothDevice.radiacode,
                signal: bluetoothDevice.signal
            )
            .layoutPriority(1)

            Spacer()

            switch bluetoothDevice.state {
            case .connected:
                Text(.ControlCenter.connected)
                    .font(.system(size: 13))
                    .foregroundStyle(.accentGreen)
                    .minimumScaleFactor(0.5)
                    .lineLimit(1)
            case .connecting:
                Text(.ControlCenter.connecting)
                    .font(.system(size: 13))
                    .foregroundStyle(.accentBlue)
                    .minimumScaleFactor(0.5)
                    .lineLimit(1)
            case .disconnected, .disconnecting:
                Text(.ControlCenter.connectionLost)
                    .font(.system(size: 13))
                    .foregroundStyle(.accentRed)
                    .minimumScaleFactor(0.5)
                    .lineLimit(2)
                    .multilineTextAlignment(.center)
            }
        }
    }
}

