    // MARK: Properties

    /// Устройство
    let radiacode: RadiaCode.Device

    /// Объект для взаимодействия с блютуз протоколом
    let peripheral: Peripheral?

    /// Состояние устройства
    var state: PeripheralImpl.ConnectionState = .disconnected
    /// RSSI
    var signal: BluetoothSignal

    /// Настройки
    var settings: Settings
    /// Прошивка
    var firmware: Firmware
    /// Пороговые значения тревог
    var alarms: Alarm
    /// Настройки спектра
    var spectrumSettings: SpectrumSettings
    /// Настройки устройства
    var configurationSettings: ConfigurationSettings = .default
    /// Базовое установленное прибором время (timeIntervalSince1970)
    var deviceBaseDate: Double = 0.0

    init(
        radiacode: RadiaCode.Device,
        signal: BluetoothSignal,
        peripheral: Peripheral?
    ) {
        self.radiacode = radiacode
        self.signal = signal
        self.peripheral = peripheral

        self.settings = .init()
        self.firmware = .init()
        self.alarms = .init()
        self.spectrumSettings = .init()

        self.setupObservers()
    }

    @discardableResult
    func send<T: BluetoothCommand>(command: T) async -> Result<T.Response, Error> {
        guard let transmition else {
            return .failure(BluetoothDeviceError.transmition)
        }
        return await transmition.send(command: command)
    }

    func start() async {
        transmition = DeviceTransmition(peripheral: self.peripheral)
        await setupSettingsObserver()
    }

    func reset() async {
        connectionStateSubscription = nil
        bluetoothSignalSubscription = nil
        settingsChangedSubscription = nil
        await stopCommands()
    }

    func stopCommands() async {
        await transmition?.stop()
        transmition = nil
    }

    deinit {
        Log.debug("BluetoothDevice Removed \(identifier)")
    }
}

