Изучил оба файла и все места использования. Вот картина:

- **`DeviceView`** — «глупый» презентационный компонент: имя модели + сигнал + идентификатор. Принимает `device: RadiaCode.Device` и `signal: BluetoothSignal`. Используется самостоятельно в `deviceRow` ([DeviceListView.swift:120](iosApp/RadiaCode/Presentation/Containers/ControlCenter/DeviceList/DeviceListView.swift:120)).
- **`ConnectionDeviceView`** — оборачивает `DeviceView` и добавляет справа метку состояния (connected / connecting / lost). Принимает целый `BluetoothDevice`. Используется в [DeviceListView.swift:62](iosApp/RadiaCode/Presentation/Containers/ControlCenter/DeviceList/DeviceListView.swift:62) и [DeviceInfoView.swift:32](iosApp/RadiaCode/Presentation/Containers/ControlCenter/DeviceInfo/DeviceInfoView.swift:32).

Да, их можно объединить. Поскольку `DeviceView` ещё используется **без** состояния, чистый способ — слить логику `ConnectionDeviceView` внутрь `DeviceView` через **опциональный `state`**: nil → как сейчас, не-nil → показываем метку состояния.

Вот что предлагаю (правок не вносил — сначала показываю).

**1. Новый `DeviceView.swift`:**

```swift
struct DeviceView: View {

    let device: RadiaCode.Device
    let signal: BluetoothSignal
    var state: PeripheralConnectionState? = nil

    var body: some View {
        HStack {
            VStack(alignment: .leading) {
                HStack {
                    Text(device.model.name)
                        .font(.system(size: 17, weight: .semibold))
                        .lineLimit(1)
                        .foregroundStyle(.textPrimary)

                    BluetoothSignalView(signal: signal)
                        .font(.system(size: 14))
                }
                Text(device.identifier)
                    .font(.system(size: 15))
                    .foregroundStyle(.textSecondary)
            }
            .layoutPriority(1)

            if let state {
                Spacer()
                connectionState(state)
            }
        }
    }

    @ViewBuilder
    private func connectionState(_ state: PeripheralConnectionState) -> some View {
        switch state {
        case .connected:
            Text(.ControlCenter.connected)
                .font(.system(size: 13))
                .foregroundStyle(.accentGreen)
                .minimumScaleFactor(0.5)
                .lineLimit(1)
        case .connecting:
            Text(.ControlCenter.connecting)
                .font(.system(size: 13))
                .foregroundStyle(.accentBlue)
                .minimumScaleFactor(0.5)
                .lineLimit(1)
        case .disconnected, .disconnecting:
            Text(.ControlCenter.connectionLost)
                .font(.system(size: 13))
                .foregroundStyle(.accentRed)
                .minimumScaleFactor(0.5)
                .lineLimit(2)
                .multilineTextAlignment(.center)
        }
    }
}

// Удобный инициализатор, чтобы места вызова остались лаконичными
extension DeviceView {
    init(bluetoothDevice: BluetoothDevice) {
        self.init(
            device: bluetoothDevice.radiacode,
            signal: bluetoothDevice.signal,
            state: bluetoothDevice.state
        )
    }
}

